import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"SkillLearnBench: Benchmarking Continual Skill Learning for Language Model Agents","description":"","frontmatter":{"title":"SkillLearnBench: Benchmarking Continual Skill Learning for Language Model Agents","authors":"Yiwei Qin, Weiran Xu, Yifei Li, Zhiqiang Hu, Xuefeng Li, Pengfei Liu","published":"2026-04-22T00:00:00.000Z","source":"https://arxiv.org/abs/2604.20087"},"headers":[],"relativePath":"research/papers/2026-04-22-skill-learn-bench-continual-skill-learning-2604-20087.md","filePath":"research/papers/2026-04-22-skill-learn-bench-continual-skill-learning-2604-20087.md","lastUpdated":1779901665000}'),s={name:"research/papers/2026-04-22-skill-learn-bench-continual-skill-learning-2604-20087.md"};function i(l,e,o,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="skilllearnbench-benchmarking-continual-skill-learning-for-language-model-agents" tabindex="-1">SkillLearnBench: Benchmarking Continual Skill Learning for Language Model Agents <a class="header-anchor" href="#skilllearnbench-benchmarking-continual-skill-learning-for-language-model-agents" aria-label="Permalink to &quot;SkillLearnBench: Benchmarking Continual Skill Learning for Language Model Agents&quot;">​</a></h1><p><strong>Authors</strong>: Yiwei Qin, Weiran Xu, Yifei Li, Zhiqiang Hu, Xuefeng Li, Pengfei Liu <strong>Published</strong>: April 22, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.20087" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.20087</a><strong>arXiv ID</strong>: 2604.20087 <strong>Categories</strong>: cs.AI, cs.CL, cs.LG</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>SkillLearnBench is a benchmark and methodology for continual skill acquisition in LLM agents — teaching agents to learn new procedural skills from experience. Baseline (no skill): 10.17%. Human-authored skills: 74.50%. Automated skill-learning methods: ~30% (ceiling). External feedback outperforms self-feedback for skill refinement. No automated method dominates across task types. Stronger base models don&#39;t reliably produce better learned skills.</p><hr><h2 id="problem-setting-continual-skill-learning" tabindex="-1">Problem Setting: Continual Skill Learning <a class="header-anchor" href="#problem-setting-continual-skill-learning" aria-label="Permalink to &quot;Problem Setting: Continual Skill Learning&quot;">​</a></h2><p>Traditional agents rely on static, pre-authored skill libraries. SkillLearnBench evaluates whether agents can <strong>learn new skills from experience</strong> — analogous to how a human employee learns new procedures over time through practice and feedback.</p><h3 id="task-setup" tabindex="-1">Task Setup <a class="header-anchor" href="#task-setup" aria-label="Permalink to &quot;Task Setup&quot;">​</a></h3><ol><li>Agent receives a task that requires a skill it doesn&#39;t currently have</li><li>Agent attempts the task (often failing or performing poorly)</li><li>Agent receives feedback (success/failure signal, external critique, or self-generated)</li><li>Agent updates its skill representation</li><li>Agent attempts similar tasks — does performance improve?</li></ol><hr><h2 id="baseline-performance" tabindex="-1">Baseline Performance <a class="header-anchor" href="#baseline-performance" aria-label="Permalink to &quot;Baseline Performance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Condition</th><th>Performance</th></tr></thead><tbody><tr><td><strong>No skills (baseline)</strong></td><td><strong>10.17%</strong></td></tr><tr><td>Best automated skill-learning method</td><td>~30%</td></tr><tr><td><strong>Human-authored skills</strong></td><td><strong>74.50%</strong></td></tr></tbody></table><p>The 74.50% → 10.17% gap (64.3pp) represents the current ceiling on automated skill learning — a large open research problem.</p><hr><h2 id="feedback-sources-compared" tabindex="-1">Feedback Sources Compared <a class="header-anchor" href="#feedback-sources-compared" aria-label="Permalink to &quot;Feedback Sources Compared&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feedback Source</th><th>Performance</th><th>Notes</th></tr></thead><tbody><tr><td><strong>External feedback</strong></td><td><strong>Higher</strong></td><td>Human critique, test suites, environment signals</td></tr><tr><td>Self-feedback</td><td>Lower</td><td>Agent critiques its own outputs</td></tr><tr><td>No feedback</td><td>Lowest</td><td>One-shot skill extraction</td></tr></tbody></table><p><strong>External feedback &gt; self-feedback</strong>: When agents critique their own skill-learning, they amplify existing biases rather than correcting them. External signals (test pass/fail, human review, environment rewards) provide genuine correction.</p><hr><h2 id="why-self-feedback-fails" tabindex="-1">Why Self-Feedback Fails <a class="header-anchor" href="#why-self-feedback-fails" aria-label="Permalink to &quot;Why Self-Feedback Fails&quot;">​</a></h2><p>Self-feedback in skill learning fails for the same reasons as SkillsBench&#39;s self-generated skills:</p><ol><li><strong>Recursive echo chamber</strong>: The agent evaluates its own skill using the same priors that created the flawed skill</li><li><strong>No ground truth</strong>: Without external reference, the agent can&#39;t detect systematic blind spots</li><li><strong>Coherence ≠ correctness</strong>: Self-generated critiques tend to focus on surface consistency rather than functional correctness</li></ol><hr><h2 id="no-method-dominates-across-task-types" tabindex="-1">No Method Dominates Across Task Types <a class="header-anchor" href="#no-method-dominates-across-task-types" aria-label="Permalink to &quot;No Method Dominates Across Task Types&quot;">​</a></h2><p>The paper tests multiple automated skill-learning methods:</p><table tabindex="0"><thead><tr><th>Method</th><th>Best Domain</th><th>Worst Domain</th></tr></thead><tbody><tr><td>In-context learning from demonstrations</td><td>Procedural tasks</td><td>Creative tasks</td></tr><tr><td>Error-driven refinement</td><td>Debugging tasks</td><td>Open-ended reasoning</td></tr><tr><td>Reward signal distillation</td><td>RL-compatible tasks</td><td>Natural language tasks</td></tr><tr><td>Constitutional self-revision</td><td>Alignment-sensitive tasks</td><td>Technical precision</td></tr></tbody></table><p><strong>Finding</strong>: No single automated method wins across all task types. Human-authored skills remain the only approach that generalizes well.</p><hr><h2 id="base-model-strength-better-learned-skills" tabindex="-1">Base Model Strength ≠ Better Learned Skills <a class="header-anchor" href="#base-model-strength-better-learned-skills" aria-label="Permalink to &quot;Base Model Strength ≠ Better Learned Skills&quot;">​</a></h2><p>A counterintuitive finding: stronger base models (measured by standard benchmarks) do <strong>not</strong> reliably produce better learned skills.</p><table tabindex="0"><thead><tr><th>Model Size / Capability</th><th>Skill Learning Rate</th></tr></thead><tbody><tr><td>Smaller/weaker models</td><td>Comparable or sometimes better</td></tr><tr><td>Larger/stronger models</td><td>Not reliably better</td></tr></tbody></table><p><strong>Hypothesis</strong>: Stronger models may over-rely on their pre-existing knowledge and resist updating toward the task-specific skill. Weaker models, having less prior knowledge, may be more receptive to learned procedures.</p><hr><h2 id="skill-representation-formats-evaluated" tabindex="-1">Skill Representation Formats Evaluated <a class="header-anchor" href="#skill-representation-formats-evaluated" aria-label="Permalink to &quot;Skill Representation Formats Evaluated&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Learnability</th><th>Executability</th></tr></thead><tbody><tr><td>Natural language prose</td><td>High</td><td>Low</td></tr><tr><td>Numbered steps</td><td>High</td><td>High</td></tr><tr><td>Pseudocode</td><td>Moderate</td><td>High</td></tr><tr><td>Code</td><td>Low</td><td>Highest</td></tr><tr><td>Structured JSON/YAML</td><td>Low</td><td>High</td></tr></tbody></table><p><strong>Numbered step format</strong> balances learnability (easy to generate from demonstrations) with executability (easy for the agent to follow during task execution).</p><hr><h2 id="key-metric-skill-transfer-rate" tabindex="-1">Key Metric: Skill Transfer Rate <a class="header-anchor" href="#key-metric-skill-transfer-rate" aria-label="Permalink to &quot;Key Metric: Skill Transfer Rate&quot;">​</a></h2><p>The benchmark introduces <strong>Skill Transfer Rate (STR)</strong>: the fraction of learned skill improvements that transfer to structurally similar but unseen tasks.</p><p>High STR = skill generalizes well (good) Low STR = skill overfits to training examples (bad)</p><p>Best automated methods achieve STR ~0.4–0.6 vs. human-authored skills at ~0.8.</p><hr><h2 id="continual-learning-without-forgetting" tabindex="-1">Continual Learning Without Forgetting <a class="header-anchor" href="#continual-learning-without-forgetting" aria-label="Permalink to &quot;Continual Learning Without Forgetting&quot;">​</a></h2><p>The benchmark also evaluates catastrophic forgetting — do newly learned skills degrade previously learned ones?</p><ul><li><strong>Isolated skill updates</strong>: No forgetting (adding new skill file doesn&#39;t affect old ones)</li><li><strong>In-context refinement</strong>: Low forgetting risk (skills stored as separate context blocks)</li><li><strong>Fine-tuning approaches</strong>: Significant forgetting risk (weight updates affect all skills)</li></ul><p>Context-storage skill representations (skills as markdown files) are catastrophic-forgetting-resistant by design.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Critical calibration for workspace skill lifecycle management:</p><ol><li><strong>10.17% (no skill) → 74.50% (human-authored)</strong>: The 64pp gap confirms that investing in high-quality human-authored skills (like the workspace&#39;s <code>research-hub</code>, <code>autoresearch</code>, <code>harness-meta</code>) is the highest-leverage improvement available.</li><li><strong>Automated methods plateau at ~30%</strong>: Don&#39;t automate skill generation for production use — current automated methods can&#39;t approach human-authored quality. Human gate on new skills remains mandatory.</li><li><strong>External feedback &gt; self-feedback</strong>: When refining skills (e.g., improving <code>research-hub</code> after observing failures), use external feedback (user reports, task success rates) not self-generated critiques.</li><li><strong>No method dominates across task types</strong>: The workspace skill library needs different approaches for different domains — a research skill and a security-review skill can&#39;t use the same generation methodology.</li><li><strong>Context-storage is forgetting-resistant</strong>: Workspace skills as <code>.md</code> files in <code>.claude/skills/</code> (context-storage) are correctly designed — no catastrophic forgetting risk unlike fine-tuned approaches.</li><li><strong>Numbered step format</strong>: The existing workspace skill format (numbered steps + I/O contracts) is empirically the best balance of learnability and executability.</li></ol>',50)])])}const k=t(s,[["render",i]]);export{u as __pageData,k as default};
